function nextRelation(metadata, msg) {
    var out_list = [];
    switch (msg.method) {
        case "createScene":
        case "editScene":
            out_list = ['createScene']
            break;
            
        case "addDevToScene":
            out_list = ['addDevToScene']
            break;
            
        case "delDevFromScene":
            out_list = ['delDevFromScene']
            break;
            
        case "delScene":
            out_list = ['delScene']
            break;

        case "createSceneController":
            out_list = ['createSceneController']
            break;
            
        case "delSceneController":
            out_list = ['delSceneController']
            break;


        case "updateSceneName":
            out_list = ['updateSceneName']
            break;
    
        default:
            out_list = ['otherMethod']
            break;
    }
    return out_list;
}
return nextRelation(metadata, msg);

