    var out_list = [];
    switch (msg.method) {
        case "createSceneRspComplete":
            out_list = ['createSceneRspComplete']
            break;
            
        case "addDevToSceneRspComplete":
            out_list = ['addDevToSceneRspComplete']
            break;
            
        case "delDevFromSceneRspComplete":
            out_list = ['delDevFromSceneRspComplete']
            break;

        default:
            out_list = ['otherMethod']
            break;
    }
    return out_list;
}
